from semantic_kernel.contents import ChatHistory

class TokenBoundedSession:
    def __init__(self, max_tokens=8000):
        self.max_tokens = max_tokens
        self.sessions = []

    def add_message(self, chat_history: ChatHistory):
        current_session = ChatHistory()
        for msg in chat_history:
            if self.current_token_count(current_session) < self.max_tokens:
                current_session.add_message(msg)
            else:
                self.sessions.append(current_session)
                current_session = ChatHistory([msg])
        self.sessions.append(current_session)

    def current_token_count(self, session):
        return sum(len(msg.content) for msg in session) // 4

session_manager = TokenBoundedSession()
